item.description:
 &lt;ul&gt;
&lt;li&gt;首次适应算法 FF&lt;/li&gt;
&lt;li&gt;循环首次适应算法 NF&lt;/li&gt;
&lt;li&gt;最佳适应算法 BF&lt;/li&gt;
&lt;li&gt;最差适应算法 WF&lt;/li&gt;
&lt;/ul&gt;
&lt;pre&gt;&lt;code class=&#34;language-c++&#34;&gt;#include &amp;lt;malloc.h&amp;gt;
#include &amp;lt;stdio.h&amp;gt;
#include &amp;lt;stdlib.h&amp;gt;

#define PROCESS_NAME_LEN 32   //进程名字长度
#define MIN_SLICE 10          //最小碎片大小
#define DEFAULT_MEM_SIZE 1024 // 默认的内存大小
#define DEFAULT_MEM_START 0   //起始地址

#define MA_FF 1 //首次适应算法
#define MA_BF 2 //最佳适应算法
#define MA_WF 3 //最坏适应算法
#define MA_NF 4 //临近适应算法（循环首次适应算法）

//空闲分区的结构体
typedef struct free_block_type &amp;#123;
    int size;
    int start_addr;
    struct free_block_type *next;
&amp;#125; free_block_type;
/*指向内存中空闲块链表的首指针*/
free_block_type *free_block;

//已分配分区的结构体
typedef struct allocated_block &amp;#123;
    int pid;
    int size;
    int start_addr;
    char process_name[PROCESS_NAME_LEN];
    struct allocated_block *next;
&amp;#125; allocated_block;
//进程分配内存块链表的首指针
struct allocated_block *allocated_block_head = NULL;

int mem_size = DEFAULT_MEM_SIZE;    // 内存大小
int ma_algorithm = MA_FF;   // 动态分区分配算法
static int pid = 0;     //  进程号
int flag = 0;   // 判断内存是否被修改标志

//函数声明
void display_menu();    // 显示主菜单
int set_mem_size();     // 设置内存大小
void set_algorithm();   // 选择当前算法
void rearrange(int algorithm);  // 为每一个进程分配完内存以后重新按已选择的算法再次排序
int new_process();      // 创建一个新的进程
int allocate_mem(struct allocated_block *ab);   // 内存分配
void kill_process();    // 杀死进程
int free_mem(struct allocated_block *ab);       // 释放杀死进程的内存块
int dispose(struct allocated_block *free_ab);   // 销毁杀死进程的结点
int display_mem_usage();    // 显示内存使用情况
allocated_block *find_process(int pid);         // 找到要杀死的进程的标号
void rearrange_FF();    // 首次适应算法
void rearrange_BF();    // 最佳适应算法
void rearrange_WF();    // 最坏适应算法
void rearrange_NF();    // 临近适应算法（循环首次适应算法）

//初始化空闲分区
free_block_type *init_free_block(int mem_size) &amp;#123;
    free_block_type *fb;
    fb = (free_block_type *)malloc(sizeof(free_block_type));
    if (fb == NULL) &amp;#123;
        printf(&amp;quot;No mem\n&amp;quot;);
        return NULL;
    &amp;#125;
    fb-&amp;gt;size = mem_size;
    fb-&amp;gt;start_addr = DEFAULT_MEM_START;
    fb-&amp;gt;next = NULL;
    return fb;
&amp;#125;

//显示主菜单
void display_menu() &amp;#123;
    printf(&amp;quot;\n&amp;quot;);
    printf(&amp;quot;1 - Set memory size (default=%d)\n&amp;quot;, DEFAULT_MEM_SIZE);
    printf(&amp;quot;2 - Select memory allocation algorithm\n&amp;quot;);
    printf(&amp;quot;3 - New process \n&amp;quot;);
    printf(&amp;quot;4 - Terminate a process \n&amp;quot;);
    printf(&amp;quot;5 - Display memory usage \n&amp;quot;);
    printf(&amp;quot;0 - Exit\n&amp;quot;);
&amp;#125;

/*设置内存大小*/
int set_mem_size() &amp;#123;
    int size;
    if (flag != 0) &amp;#123; /*flag标志防止内存被再次设置*/
        printf(&amp;quot;Cannot set memory size again\n&amp;quot;);
        return 0;
    &amp;#125;
    printf(&amp;quot;Total memory size =&amp;quot;);
    scanf(&amp;quot;%d&amp;quot;, &amp;amp;size);
    if (size &amp;gt; 0) &amp;#123;
        mem_size = size;
        free_block-&amp;gt;size = mem_size; /*设置初始大小为 1024*/
    &amp;#125;
    flag = 1;
    return 1;
&amp;#125;
/*选择当前算法*/
void set_algorithm() &amp;#123;
    int algorithm;
    printf(&amp;quot;\t1 - First Fit\n&amp;quot;);
    printf(&amp;quot;\t2 - Best Fit \n&amp;quot;);
    printf(&amp;quot;\t3 - Worst Fit \n&amp;quot;);
    printf(&amp;quot;\t4 - Next Fit\n&amp;quot;);
    printf(&amp;quot;Please input your choice : &amp;quot;);
    scanf(&amp;quot;%d&amp;quot;, &amp;amp;algorithm);
    if (algorithm &amp;gt;= 1 &amp;amp;&amp;amp; algorithm &amp;lt;= 4)
        ma_algorithm = algorithm;

    rearrange(ma_algorithm);
&amp;#125;

/*为每一个进程分配完内存以后重新按已选择的算法再次排序*/
void rearrange(int algorithm) &amp;#123;
    switch (algorithm) &amp;#123;
    case MA_FF:
        rearrange_FF();
        break;
    case MA_BF:
        rearrange_BF();
        break;
    case MA_WF:
        rearrange_WF();
        break;
    case MA_NF:
        rearrange_NF();
        break;
    &amp;#125;
&amp;#125;

/*首次适应算法，按地址的大小由小到大排序*/
void rearrange_FF() &amp;#123;
    free_block_type *temp, *p = NULL;
    free_block_type *head = NULL;
    int current_min_addr;

    if (free_block) &amp;#123;
        temp = free_block;
        current_min_addr = free_block-&amp;gt;start_addr;
        while (temp-&amp;gt;next != NULL) &amp;#123;
            if (temp-&amp;gt;next-&amp;gt;start_addr &amp;lt; current_min_addr) &amp;#123;
                current_min_addr = temp-&amp;gt;next-&amp;gt;start_addr;
                p = temp;
            &amp;#125;
            temp = temp-&amp;gt;next;
        &amp;#125;
        if (p != NULL) &amp;#123;
            temp = p-&amp;gt;next;
            p-&amp;gt;next = p-&amp;gt;next-&amp;gt;next;
            temp-&amp;gt;next = free_block;
            free_block = temp;
        &amp;#125;
        head = free_block;
        p = head;
        temp = head-&amp;gt;next;
        while (head-&amp;gt;next != NULL) &amp;#123;
            current_min_addr = head-&amp;gt;next-&amp;gt;start_addr;
            while (temp-&amp;gt;next != NULL) &amp;#123;
                if (temp-&amp;gt;next-&amp;gt;start_addr &amp;lt; current_min_addr) &amp;#123;
                    current_min_addr = temp-&amp;gt;next-&amp;gt;start_addr;
                    p = temp;
                &amp;#125;
                temp = temp-&amp;gt;next;
            &amp;#125;
            if (p-&amp;gt;next != head-&amp;gt;next) &amp;#123;
                temp = p-&amp;gt;next;
                p-&amp;gt;next = p-&amp;gt;next-&amp;gt;next;
                temp-&amp;gt;next = head-&amp;gt;next;
                head-&amp;gt;next = temp;
            &amp;#125;
            head = head-&amp;gt;next;
            temp = head-&amp;gt;next;
            p = head;
        &amp;#125;
    &amp;#125;
    return;
&amp;#125;

/*最佳适应算法，按内存块的大小由小到大排序*/
void rearrange_BF() &amp;#123;
    free_block_type *temp, *p = NULL;
    free_block_type *head = NULL;
    int current_min_size = free_block-&amp;gt;size;

    temp = free_block;
    while (temp-&amp;gt;next != NULL) &amp;#123;
        if (temp-&amp;gt;next-&amp;gt;size &amp;lt; current_min_size) &amp;#123;
            current_min_size = temp-&amp;gt;next-&amp;gt;size;
            p = temp;
        &amp;#125;
        temp = temp-&amp;gt;next;
    &amp;#125;
    if (p != NULL) &amp;#123;
        temp = p-&amp;gt;next;
        p-&amp;gt;next = p-&amp;gt;next-&amp;gt;next;
        temp-&amp;gt;next = free_block;
        free_block = temp;
    &amp;#125;
    head = free_block;
    p = head;
    temp = head-&amp;gt;next;
    while (head-&amp;gt;next != NULL) &amp;#123;
        current_min_size = head-&amp;gt;next-&amp;gt;size;
        while (temp-&amp;gt;next != NULL) &amp;#123;
            if (temp-&amp;gt;next-&amp;gt;size &amp;lt; current_min_size) &amp;#123;
                current_min_size = temp-&amp;gt;next-&amp;gt;size;
                p = temp;
            &amp;#125;
            temp = temp-&amp;gt;next;
        &amp;#125;
        if (p-&amp;gt;next != head-&amp;gt;next) &amp;#123;
            temp = p;
            p-&amp;gt;next = p-&amp;gt;next-&amp;gt;next;
            temp-&amp;gt;next = head-&amp;gt;next;
            head-&amp;gt;next = temp;
        &amp;#125;
        head = head-&amp;gt;next;
        temp = head-&amp;gt;next;
        p = head;
    &amp;#125;
&amp;#125;

/*最坏适应算法，按地址块的大小从大到小排序*/
void rearrange_WF() &amp;#123;
    free_block_type *temp, *p = NULL;
    free_block_type *head = NULL;
    int current_max_size = free_block-&amp;gt;size;
    temp = free_block;
    while (temp-&amp;gt;next != NULL) &amp;#123;
        if (temp-&amp;gt;next-&amp;gt;size &amp;gt; current_max_size) &amp;#123;
            current_max_size = temp-&amp;gt;next-&amp;gt;size;
            p = temp;
        &amp;#125;
        temp = temp-&amp;gt;next;
    &amp;#125;
    if (p != NULL) &amp;#123;
        temp = p;
        p-&amp;gt;next = p-&amp;gt;next-&amp;gt;next;
        temp-&amp;gt;next = free_block;
        free_block = temp;
    &amp;#125;
    head = free_block;
    p = head;
    temp = head-&amp;gt;next;
    while (head-&amp;gt;next != NULL) &amp;#123;
        current_max_size = head-&amp;gt;next-&amp;gt;size;
        while (temp-&amp;gt;next != NULL) &amp;#123;
            if (temp-&amp;gt;next-&amp;gt;size &amp;gt; current_max_size) &amp;#123;
                current_max_size = temp-&amp;gt;next-&amp;gt;size;
                p = temp;
            &amp;#125;
            temp = temp-&amp;gt;next;
        &amp;#125;
        if (p-&amp;gt;next != head-&amp;gt;next) &amp;#123;
            temp = p-&amp;gt;next;
            p-&amp;gt;next = p-&amp;gt;next-&amp;gt;next;
            temp-&amp;gt;next = head-&amp;gt;next;
            head-&amp;gt;next = temp;
        &amp;#125;
        head = head-&amp;gt;next;
        temp = head-&amp;gt;next;
        p = head;
    &amp;#125;
    return;
&amp;#125;

// 临近适应算法（循环首次适应算法）
struct free_block_type *NF_tmp = NULL;
void rearrange_NF()&amp;#123;
    free_block_type *temp, *p = NULL;
    free_block_type *head = NULL;
    int current_min_addr;

    if (free_block) &amp;#123;
        temp = free_block;
        current_min_addr = free_block-&amp;gt;start_addr;
        // 找到最小的地址
        while (temp-&amp;gt;next != NULL) &amp;#123;
            if (temp-&amp;gt;next-&amp;gt;start_addr &amp;lt; current_min_addr) &amp;#123;
                current_min_addr = temp-&amp;gt;next-&amp;gt;start_addr;
                p = temp;
            &amp;#125;
            temp = temp-&amp;gt;next;
        &amp;#125; // 让最小的地址成为空闲内存链表头
        if (p != NULL) &amp;#123;
            temp = p-&amp;gt;next;
            p-&amp;gt;next = p-&amp;gt;next-&amp;gt;next;
            temp-&amp;gt;next = free_block;
            free_block = temp;
        &amp;#125;
        head = free_block;
        p = head;
        temp = head-&amp;gt;next;
        while (head-&amp;gt;next != NULL) &amp;#123;    // 从头开始向后遍历，把最小的地址的内存逐次接起来
            current_min_addr = head-&amp;gt;next-&amp;gt;start_addr;
            while (temp-&amp;gt;next != NULL) &amp;#123;    // 找到剩余最小的地址的内存
                if (temp-&amp;gt;next-&amp;gt;start_addr &amp;lt; current_min_addr) &amp;#123;
                    current_min_addr = temp-&amp;gt;next-&amp;gt;start_addr;
                    p = temp;
                &amp;#125;
                temp = temp-&amp;gt;next;
            &amp;#125;
            if (p-&amp;gt;next != head-&amp;gt;next) &amp;#123;    // 把找到的最小的接起来
                temp = p-&amp;gt;next;
                p-&amp;gt;next = p-&amp;gt;next-&amp;gt;next;
                temp-&amp;gt;next = head-&amp;gt;next;
                head-&amp;gt;next = temp;      // 接上新的较小的头
            &amp;#125; 
            head = head-&amp;gt;next;  // 继续向后遍历
            temp = head-&amp;gt;next;
            p = head;
        &amp;#125;
    &amp;#125;
    return;
&amp;#125;


//创建一个新的进程
int new_process() &amp;#123;
    struct allocated_block *ab;
    int size;
    int ret;
    ab = (struct allocated_block *)malloc(sizeof(struct allocated_block));
    if (!ab)
        exit(-5);
    ab-&amp;gt;next = NULL;
    pid++;
    sprintf(ab-&amp;gt;process_name, &amp;quot;PROCESS-%02d&amp;quot;, pid);
    ab-&amp;gt;pid = pid;
    printf(&amp;quot;Memory for %s:&amp;quot;, ab-&amp;gt;process_name);
    printf(&amp;quot;Please input you want to allocate process&#39; size : &amp;quot;);
    scanf(&amp;quot;%d&amp;quot;, &amp;amp;size);
    if (size &amp;gt; 0) &amp;#123;

        ab-&amp;gt;size = size;
    &amp;#125;
    ret = allocate_mem(ab);
    if ((ret == 1) &amp;amp;&amp;amp; (allocated_block_head == NULL)) &amp;#123;
        allocated_block_head = ab;
        return 1;
    &amp;#125;

    else if (ret == 1) &amp;#123;
        ab-&amp;gt;next = allocated_block_head;
        allocated_block_head = ab;
        return 2;
    &amp;#125; else if (ret == -1) &amp;#123;
        printf(&amp;quot;Allocation fail\n&amp;quot;);
        pid--;
        free(ab);
        return -1;
    &amp;#125;
    return 3;
&amp;#125;

// NF专属内存分配
int allocate_mem_NF(struct allocated_block *ab, int ab_size) &amp;#123;
    struct free_block_type *fbt, *pre, *temp, *work, *F = NULL;
    int request_size = ab_size;
    // 与上一次位置有关
    if (NF_tmp == free_block || NF_tmp == NULL) &amp;#123; // 从头或者首次分配
        F = NULL;
        NF_tmp = free_block;
    &amp;#125; else
        F = NF_tmp;     // F记录保存上次位置，作为循环判断条件
    fbt = NF_tmp;
    pre = fbt;
    do &amp;#123;
        if (F != NULL &amp;amp;&amp;amp; fbt == NULL)
            fbt = free_block;
        if (fbt-&amp;gt;size &amp;gt;= request_size) &amp;#123;
            NF_tmp = fbt;
            if (fbt-&amp;gt;size - request_size &amp;gt;= MIN_SLICE) &amp;#123;    /*分配后空闲空间足够大，则分割*/
                // mem_size -= request_size;
                fbt-&amp;gt;size -= request_size;
                ab-&amp;gt;start_addr = fbt-&amp;gt;start_addr;
                fbt-&amp;gt;start_addr += request_size;
                NF_tmp = fbt;   // 重新记录分配位置
            &amp;#125; else if ((fbt-&amp;gt;size - request_size) &amp;lt; MIN_SLICE) &amp;#123;                /*分割后空闲区成为小碎片，一起分配*/
                // mem_size -= fbt-&amp;gt;size;
                if (pre == free_block)
                    free_block = fbt-&amp;gt;next;
                else if (pre == fbt)
                    for (pre = free_block; pre-&amp;gt;next != NULL; pre = pre-&amp;gt;next)
                        if (pre-&amp;gt;next == fbt)
                            break;
                pre-&amp;gt;next = fbt-&amp;gt;next;
                NF_tmp = fbt-&amp;gt;next;     // 重新记录分配位置
                ab-&amp;gt;start_addr = fbt-&amp;gt;start_addr;
                ab-&amp;gt;size = fbt-&amp;gt;size;
                free(fbt);
            &amp;#125; else &amp;#123;
                temp = free_block;
                while (temp != NULL) &amp;#123;
                    work = temp-&amp;gt;next;

                    if (work != NULL) &amp;#123;     /*如果当前空闲区与后面的空闲区相连，则合并*/
                        if (temp-&amp;gt;start_addr + temp-&amp;gt;size == work-&amp;gt;start_addr) &amp;#123;
                            temp-&amp;gt;size += work-&amp;gt;size;
                            temp-&amp;gt;next = work-&amp;gt;next;
                            if (NF_tmp == work)
                                NF_tmp = temp;
                            free(work);
                            continue;
                        &amp;#125;
                    &amp;#125;

                    temp = temp-&amp;gt;next;
                &amp;#125;
                rearrange(ma_algorithm); /*重新按当前的算法排列空闲区*/
            &amp;#125;
            return 1;
        &amp;#125;
        pre = fbt;
        fbt = fbt-&amp;gt;next;
    &amp;#125; while (fbt != F);     // 判断fbt是否循环完一圈
    return -1;
&amp;#125;

//内存分配
int allocate_mem(struct allocated_block *ab) &amp;#123;
    if(ma_algorithm == MA_NF) &amp;#123;
        return allocate_mem_NF(ab, ab-&amp;gt;size);
    &amp;#125;
    free_block_type *fbt, *pre;
    free_block_type *temp, *p, *p1;
    allocated_block *q;
    int request_size = ab-&amp;gt;size;
    int sum = 0;
    int max;
    fbt = pre = free_block;
    // 若有空闲内存
    if (fbt) &amp;#123;
        if (ma_algorithm == MA_WF) &amp;#123;
            // 若是最坏适应算法且最大的空闲内存也不够
            if (fbt == NULL || fbt-&amp;gt;size &amp;lt; request_size)
                return -1;
        &amp;#125; else &amp;#123;    // 若不是WF则是由小到大排列，遍历空闲内存寻找需要的大小
            while (fbt != NULL &amp;amp;&amp;amp; fbt-&amp;gt;size &amp;lt; request_size) &amp;#123;
                pre = fbt;
                fbt = fbt-&amp;gt;next;
            &amp;#125;
        &amp;#125; // 遍历完仍旧找不到
        if (fbt == NULL || fbt-&amp;gt;size &amp;lt; request_size) &amp;#123;
            if (free_block-&amp;gt;next != NULL) &amp;#123;     // 将剩余内存空间相加看是否足够
                sum = free_block-&amp;gt;size;
                temp = free_block-&amp;gt;next;
                while (temp != NULL) &amp;#123;
                    sum += temp-&amp;gt;size;
                    if (sum &amp;gt;= request_size)
                        break;
                    temp = temp-&amp;gt;next;
                &amp;#125;
                if (temp == NULL) // 还不够，退出
                    return -1;
                else &amp;#123;  // 足够
                    pre = free_block;
                    max = free_block-&amp;gt;start_addr;
                    fbt = free_block;
                    while (temp-&amp;gt;next != pre) &amp;#123;     // 找到这些块的最大地址
                        if (max &amp;lt; pre-&amp;gt;start_addr) &amp;#123;
                            max = pre-&amp;gt;start_addr;
                            fbt = pre;
                        &amp;#125;
                        pre = pre-&amp;gt;next;
                    &amp;#125;
                    pre = free_block;

                    while (pre != temp-&amp;gt;next) &amp;#123;
                        q = allocated_block_head;
                        p = free_block;

                        while (q != NULL) &amp;#123;     // 向前推 
                            if (q-&amp;gt;start_addr &amp;gt; pre-&amp;gt;start_addr)
                                q-&amp;gt;start_addr = q-&amp;gt;start_addr - pre-&amp;gt;size;
                            q = q-&amp;gt;next;
                        &amp;#125;
                        while (p != NULL) &amp;#123;
                            if (p-&amp;gt;start_addr &amp;gt; pre-&amp;gt;start_addr)
                                p-&amp;gt;start_addr = p-&amp;gt;start_addr - pre-&amp;gt;size;
                            p = p-&amp;gt;next;
                        &amp;#125;

                        pre = pre-&amp;gt;next;
                    &amp;#125;

                    pre = free_block;
                    while (pre != temp-&amp;gt;next) &amp;#123;

                        p1 = pre-&amp;gt;next;
                        if (pre == fbt)     // 最大块
                            break;
                        free(pre);
                        pre = p1;
                    &amp;#125;
                    q = allocated_block_head;
                    free_block = fbt;
                    free_block-&amp;gt;start_addr = q-&amp;gt;start_addr + q-&amp;gt;size;

                    free_block-&amp;gt;size = sum;
                    free_block-&amp;gt;next = temp-&amp;gt;next;
                    if (free_block-&amp;gt;size - request_size &amp;lt; MIN_SLICE) &amp;#123;  // 分割后太小就一起分割 
                        ab-&amp;gt;size = free_block-&amp;gt;size;
                        ab-&amp;gt;start_addr = free_block-&amp;gt;start_addr;
                        pre = free_block;
                        free_block = free_block-&amp;gt;next;
                        free(pre);
                    &amp;#125; else &amp;#123;    // 分割内存
                        ab-&amp;gt;start_addr = free_block-&amp;gt;start_addr;
                        free_block-&amp;gt;start_addr =
                            free_block-&amp;gt;start_addr + request_size;
                        free_block-&amp;gt;size = free_block-&amp;gt;size - request_size;
                    &amp;#125;
                &amp;#125;
            &amp;#125; else   // 剩余空间相加仍旧不够
                return -1;
        &amp;#125; else &amp;#123;    // 遍历空闲内存找到了足够大的
            if (fbt-&amp;gt;size - request_size &amp;lt; MIN_SLICE) &amp;#123;     // 分割后太小就一起分割 
                ab-&amp;gt;size = fbt-&amp;gt;size;
                ab-&amp;gt;start_addr = fbt-&amp;gt;start_addr;
                if (pre-&amp;gt;next == free_block) &amp;#123;
                    free_block = fbt-&amp;gt;next;
                &amp;#125; else &amp;#123;
                    pre-&amp;gt;next = fbt-&amp;gt;next;
                &amp;#125;
                free_block = fbt-&amp;gt;next;
                free(fbt);
            &amp;#125; else &amp;#123;    // 分割内存
                ab-&amp;gt;start_addr = fbt-&amp;gt;start_addr;
                fbt-&amp;gt;start_addr = fbt-&amp;gt;start_addr + request_size;
                fbt-&amp;gt;size = fbt-&amp;gt;size - request_size;
            &amp;#125;
        &amp;#125;
        rearrange(ma_algorithm);
        return 1;
    &amp;#125; else &amp;#123;    // 无空闲内存
        printf(&amp;quot;Free Memory already has been allocated over: &amp;quot;);
        return -1;
    &amp;#125;
&amp;#125;

//选择杀死一个进程
void kill_process() &amp;#123;
    struct allocated_block *ab;
    int pid;
    printf(&amp;quot;Kill Process, pid=&amp;quot;);
    scanf(&amp;quot;%d&amp;quot;, &amp;amp;pid);
    ab = find_process(pid);
    if (ab != NULL) &amp;#123;
        free_mem(ab);
        dispose(ab);
    &amp;#125;
&amp;#125;

//找到要杀死的进程的标号
allocated_block *find_process(int pid) &amp;#123;
    allocated_block *abb;
    abb = allocated_block_head;
    if (abb-&amp;gt;pid == pid) &amp;#123;
        return abb;
    &amp;#125;
    abb = allocated_block_head-&amp;gt;next;
    while (abb-&amp;gt;next != NULL) &amp;#123;
        if (abb-&amp;gt;pid == pid)
            return abb;
        abb = abb-&amp;gt;next;
    &amp;#125;
    return abb;
&amp;#125;

//释放杀死进程的内存块
int free_mem(struct allocated_block *ab) &amp;#123;
    int algorithm = ma_algorithm;
    struct free_block_type *fbt, *pre;
    fbt = (struct free_block_type *)malloc(sizeof(struct free_block_type));
    pre = (struct free_block_type *)malloc(sizeof(struct free_block_type));
    if (!fbt)
        return -1;

    fbt-&amp;gt;start_addr = ab-&amp;gt;start_addr;
    fbt-&amp;gt;size = ab-&amp;gt;size;
    fbt-&amp;gt;next = free_block;
    free_block = fbt;
    rearrange_FF();
    pre-&amp;gt;next = free_block;
    pre-&amp;gt;size = 0;
    while (pre-&amp;gt;next &amp;amp;&amp;amp; (pre-&amp;gt;next-&amp;gt;start_addr != fbt-&amp;gt;start_addr))
        pre = pre-&amp;gt;next;
    if (pre-&amp;gt;size != 0 &amp;amp;&amp;amp; fbt-&amp;gt;next != NULL) &amp;#123;
        if (((pre-&amp;gt;start_addr + pre-&amp;gt;size) == fbt-&amp;gt;start_addr) &amp;amp;&amp;amp;
            ((fbt-&amp;gt;start_addr + fbt-&amp;gt;size) == fbt-&amp;gt;next-&amp;gt;start_addr)) &amp;#123;
            pre-&amp;gt;size = pre-&amp;gt;size + fbt-&amp;gt;size + fbt-&amp;gt;next-&amp;gt;size;
            pre-&amp;gt;next = fbt-&amp;gt;next-&amp;gt;next;
            free(fbt-&amp;gt;next);
            free(fbt);
        &amp;#125; else if ((pre-&amp;gt;start_addr + pre-&amp;gt;size) == fbt-&amp;gt;start_addr) &amp;#123;
            pre-&amp;gt;size = pre-&amp;gt;size + fbt-&amp;gt;size;
            pre-&amp;gt;next = fbt-&amp;gt;next;
            free(fbt);
        &amp;#125; else if (fbt-&amp;gt;start_addr + fbt-&amp;gt;size == fbt-&amp;gt;next-&amp;gt;start_addr) &amp;#123;
            fbt-&amp;gt;size = fbt-&amp;gt;size + fbt-&amp;gt;next-&amp;gt;size;
            fbt-&amp;gt;next = fbt-&amp;gt;next-&amp;gt;next;
            free(fbt-&amp;gt;next);
        &amp;#125;
    &amp;#125; else if ((pre-&amp;gt;size == 0) &amp;amp;&amp;amp; fbt-&amp;gt;next) &amp;#123;
        if ((fbt-&amp;gt;start_addr + fbt-&amp;gt;size) == fbt-&amp;gt;next-&amp;gt;start_addr) &amp;#123;
            fbt-&amp;gt;size = fbt-&amp;gt;size + fbt-&amp;gt;next-&amp;gt;size;
            fbt-&amp;gt;next = fbt-&amp;gt;next-&amp;gt;next;
            free_block = fbt;
            free(fbt-&amp;gt;next);
        &amp;#125;
    &amp;#125; else if (fbt-&amp;gt;next == NULL) &amp;#123;
        if ((pre-&amp;gt;start_addr + pre-&amp;gt;size) == fbt-&amp;gt;start_addr) &amp;#123;
            pre-&amp;gt;size = pre-&amp;gt;size + fbt-&amp;gt;size;
            pre-&amp;gt;next = fbt-&amp;gt;next;
            free(fbt);
        &amp;#125;
    &amp;#125;
    rearrange(algorithm);

    return 1;
&amp;#125;

//销毁杀死进程的结点
int dispose(struct allocated_block *free_ab) &amp;#123;
    struct allocated_block *pre, *ab;

    if (free_ab == allocated_block_head) &amp;#123;
        allocated_block_head = allocated_block_head-&amp;gt;next;
        free(free_ab);
        return 1;
    &amp;#125;
    pre = allocated_block_head;
    ab = allocated_block_head-&amp;gt;next;
    while (ab != free_ab) &amp;#123;
        pre = ab;
        ab = ab-&amp;gt;next;
    &amp;#125;
    pre-&amp;gt;next = ab-&amp;gt;next;
    free(ab);
    return 2;
&amp;#125;

//显示内存使用情况
int display_mem_usage() &amp;#123;
    struct free_block_type *fbt = free_block;
    struct allocated_block *ab = allocated_block_head;
    printf(&amp;quot;----------------------------------------------------------\n&amp;quot;);

    if (fbt == NULL) &amp;#123;
        printf(&amp;quot;Free Memory already used over !\n&amp;quot;);
    &amp;#125;
    printf(&amp;quot;----------------------------------------------------------\n&amp;quot;);

    if (fbt) &amp;#123;
        printf(&amp;quot;Free Memory:\n&amp;quot;);
        printf(&amp;quot;%20s %20s\n&amp;quot;, &amp;quot; start_addr&amp;quot;, &amp;quot; size&amp;quot;);
        while (fbt != NULL) &amp;#123;
            printf(&amp;quot;%20d %20d\n&amp;quot;, fbt-&amp;gt;start_addr, fbt-&amp;gt;size);
            fbt = fbt-&amp;gt;next;
        &amp;#125;
    &amp;#125;

    printf(&amp;quot;\nUsed Memory:\n&amp;quot;);
    printf(&amp;quot;%10s %20s %15s %10s\n&amp;quot;, &amp;quot;PID&amp;quot;, &amp;quot;ProcessName&amp;quot;, &amp;quot;start_addr&amp;quot;,
           &amp;quot; size&amp;quot;);
    while (ab != NULL) &amp;#123;
        printf(&amp;quot;%10d %20s %15d %10d\n&amp;quot;, ab-&amp;gt;pid, ab-&amp;gt;process_name,
               ab-&amp;gt;start_addr, ab-&amp;gt;size);
        ab = ab-&amp;gt;next;
    &amp;#125;
    printf(&amp;quot;----------------------------------------------------------\n&amp;quot;);
    return 0;
&amp;#125;

//退出，销毁所有链表
void do_exit() &amp;#123;
    free_block_type *temp;
    allocated_block *temp1;

    temp = free_block-&amp;gt;next;
    while (temp != NULL) &amp;#123;
        free_block-&amp;gt;next = temp-&amp;gt;next;
        free(temp);
        temp = free_block-&amp;gt;next;
    &amp;#125;
    free(free_block);

    if(!allocated_block_head)
        return;
    temp1 = allocated_block_head-&amp;gt;next;
    while (temp1 != NULL) &amp;#123;
        allocated_block_head-&amp;gt;next = temp1-&amp;gt;next;
        free(temp1);
        temp1 = allocated_block_head-&amp;gt;next;
    &amp;#125;
    free(allocated_block_head-&amp;gt;next);
&amp;#125;
//主函数
int main() &amp;#123;
    char choice;
    pid = 0;
    free_block = init_free_block(mem_size);
    while (1) &amp;#123;
        display_menu();
        fflush(stdin);

        choice = getchar();
        switch (choice) &amp;#123;
        case &#39;1&#39;:
            set_mem_size();
            break;
        case &#39;2&#39;:
            set_algorithm();
            flag = 1;
            break;
        case &#39;3&#39;:
            new_process();
            flag = 1;
            break;
        case &#39;4&#39;:
            kill_process();
            flag = 1;
            break;
        case &#39;5&#39;:
            display_mem_usage();
            flag = 1;
            break;
        case &#39;0&#39;:
            do_exit();
            exit(0);
        default:
            break;
        &amp;#125;
    &amp;#125;
    return 0;
&amp;#125;
&lt;/code&gt;&lt;/pre&gt;

 &lt;h1 id=&#34;计算机图形学学习笔记&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#计算机图形学学习笔记&#34;&gt;#&lt;/a&gt; 计算机图形学 —— 学习笔记&lt;/h1&gt;
&lt;h2 id=&#34;前言&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#前言&#34;&gt;#&lt;/a&gt; 前言&lt;/h2&gt;
&lt;div class=&#34;note info&#34;&gt;
&lt;p&gt;&lt;strong&gt;终于迈出学习计算机图形学的第一步了......&lt;/strong&gt;&lt;/p&gt;
&lt;/div&gt;
&lt;p&gt;&lt;ins class=&#34;dot&#34;&gt;喜欢上计算机图形学的起因大概是听了传奇程序员&lt;mark&gt;约翰・卡马克&lt;/mark&gt;的故事，这位推动了 3D 发展的大佬给我留下了无比深刻的印象。&lt;/ins&gt;&lt;/p&gt;
&lt;p&gt;&lt;img data-src=&#34;https://tva4.sinaimg.cn/large/008ieO5lly8gqmb5tqfs4j30go093wfi.jpg&#34; alt=&#34;约翰·卡马克&#34; title=&#34;约翰·卡马克&#34; /&gt;&lt;/p&gt;
&lt;p&gt;&lt;s class=&#34;danger&#34;&gt;再加上我对渲染、光追、VR、AR 等等也都很感兴趣，就想去了解更多，于是也就有了这篇记录博客。&lt;/s&gt;&lt;/p&gt;
&lt;h2 id=&#34;计划第一步games101-现代计算机图形学入门&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#计划第一步games101-现代计算机图形学入门&#34;&gt;#&lt;/a&gt; 计划第一步 ——GAMES101 - 现代计算机图形学入门&lt;/h2&gt;
&lt;p&gt;&lt;ins class=&#34;wavy&#34;&gt;计划先观看闫令琪大佬的视屏：GAMES101 - 现代计算机图形学入门&lt;/ins&gt;&lt;/p&gt;
&lt;p&gt;&lt;div class=&#34;links&#34;&gt;&lt;div class=&#34;item&#34; title=&#34;闫令琪&#34; style=&#34;--block-color:#e9546b;&#34;&gt;&lt;span class=&#34;exturl image&#34; data-url=&#34;aHR0cHM6Ly93d3cuYmlsaWJpbGkuY29tL3ZpZGVvL0JWMVg3NDExRjc0ND9mcm9tPXNlYXJjaCZzZWlkPTE2MjI4MzA3NTExNjQ5MTIzNTYw&#34; data-background-image=&#34;https://tva4.sinaimg.cn/large/008ieO5lly8gpxh7gr2ajj308c08c3yp.jpg&#34;&gt;&lt;/span&gt;
          &lt;div class=&#34;info&#34;&gt;
          &lt;span class=&#34;exturl title&#34; data-url=&#34;aHR0cHM6Ly93d3cuYmlsaWJpbGkuY29tL3ZpZGVvL0JWMVg3NDExRjc0ND9mcm9tPXNlYXJjaCZzZWlkPTE2MjI4MzA3NTExNjQ5MTIzNTYw&#34;&gt;GAMES101-现代计算机图形学入门&lt;/span&gt;
          &lt;p class=&#34;desc&#34;&gt;闫令琪&lt;/p&gt;
          &lt;/div&gt;&lt;/div&gt;&lt;/div&gt;&lt;/p&gt;
&lt;div class=&#34;note success&#34;&gt;
&lt;p&gt;&lt;s class=&#34;danger&#34;&gt;从入门到放弃的&lt;/s&gt;	&lt;strong&gt;进度&lt;/strong&gt;&lt;/p&gt;
&lt;/div&gt;
&lt;p&gt;编辑器当然还是用我最喜欢的 VIM	&lt;span class=&#34;spoiler&#34; title=&#34;你知道得太多了&#34;&gt;虽然视屏里的老师及其不推荐，无它，我插件安的多一样好用！&lt;/span&gt;&lt;/p&gt;
&lt;p&gt;开发环境我决定使用实体机，&lt;s class=&#34;danger&#34;&gt;因为不喜欢用虚拟机，尤其是其他发行版的 Linux......&lt;/s&gt;&lt;/p&gt;
&lt;p&gt;视屏里的作业首先需要下载编译器和两个库，ArchLinux 可以直接执行以下命令安装：&lt;/p&gt;
&lt;figure class=&#34;highlight bash&#34;&gt;&lt;figcaption data-lang=&#34;bash&#34;&gt;&lt;/figcaption&gt;&lt;table&gt;&lt;tr&gt;&lt;td data-num=&#34;1&#34;&gt;&lt;/td&gt;&lt;td&gt;&lt;pre&gt;&lt;span class=&#34;token function&#34;&gt;sudo&lt;/span&gt; pacman -S gcc &lt;span class=&#34;token function&#34;&gt;make&lt;/span&gt; cmake eigen opencv vtk hdf5 glew&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;&lt;p&gt;Eigen 是矩阵库，OpenCV 是视觉和机器学习软件库（实测最新的版本 4.x 也可以）&lt;/p&gt;
&lt;p&gt;gcc 是编译器，&lt;em&gt;CMake&lt;/em&gt; 是一个跨平台的安装（编译）工具&lt;/p&gt;
&lt;p&gt;其他部分是依赖&lt;/p&gt;
&lt;h3 id=&#34;视屏进度&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#视屏进度&#34;&gt;#&lt;/a&gt; 视屏进度&lt;/h3&gt;
&lt;div class=&#34;tab&#34; data-id=&#34;id1&#34; data-title=&#34;P1——P5&#34;&gt;
&lt;ul class=&#34;task-list&#34;&gt;
&lt;li class=&#34;task-list-item&#34;&gt;
&lt;p&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_0&#34; checked=&#34;true&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_0&#34;&gt; P1	图形学概述&lt;/label&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;
&lt;p&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_1&#34; checked=&#34;true&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_1&#34;&gt; P2    线性代数回顾：点乘 (方向角度)、叉乘 (判断左右、内外)、矩阵 (基础概念)&lt;/label&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;
&lt;p&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_2&#34; checked=&#34;true&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_2&#34;&gt; P3    2D 仿射变换：(线性变换) 旋转、平移 (水温逐渐升高)&lt;/label&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;
&lt;p&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_3&#34; checked=&#34;true&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_3&#34;&gt; P4    3D 变换、观测 (视图、投影)、正交、透视投影 (青蛙煮熟了)&lt;/label&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;
&lt;p&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_4&#34; checked=&#34;true&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_4&#34;&gt; P5    三角形光栅化 (采样)、缩放、平移、旋转&lt;/label&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/div&gt;
&lt;div class=&#34;tab&#34; data-id=&#34;id1&#34; data-title=&#34;P6——P10&#34;&gt;
&lt;ul class=&#34;task-list&#34;&gt;
&lt;li class=&#34;task-list-item&#34;&gt;
&lt;p&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_5&#34; checked=&#34;true&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_5&#34;&gt; P6	 光栅化 (反走样、深度缓冲)、Artifacts、先做模糊 (滤波) 再采样、时域的卷积 = 频域的乘积、MSAA (多重采样抗锯齿，同一像素增加了采样点)、FXAA (快速近似抗锯齿，不是采样，先模糊，再替换边界锯齿)、TAA (时间近似抗锯齿，复用上一帧)、Super resolution (超分辨率)、DLSS &lt;span class=&#34;spoiler&#34; title=&#34;你知道得太多了&#34;&gt;深度学习 == 猜，淦&lt;/span&gt;&lt;/label&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;
&lt;p&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_6&#34; checked=&#34;true&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_6&#34;&gt; P7     可见性遮挡 (深度缓存)、着色、画家算法、Z-Buffer (例如深度一样游戏会闪就是)、shading (着色不同材质)、漫反射 (和观测方向无关)&lt;/label&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;
&lt;p&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_7&#34; checked=&#34;true&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_7&#34;&gt; P8     Blinn-Phong 着色模型、高光 (半程向量和法向量是否足够接近，余弦的指数一般用 100——200)、环境光 (大胆假设：常数)、着色频率 (每个面片、顶点、像素)、实时渲染 (图形) 管线、shader (着色器)、纹理映射&lt;/label&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;
&lt;p&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_8&#34; checked=&#34;true&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_8&#34;&gt; P9     纹理的应用、重心坐标插值 (为得到顶点间平滑的过度)、纹理贴图 (纹理低分辨率时 Bilinear 双线性插值)、双向三阶插值 (Bicubic)、纹理太大会丢失细节 (又是走样！)、Mipmap (范围查询、只能近似方形)、log2 L、三线性插值 (纹理内部双线性插值，Mipmap 层之间插值) 得到连续的图、Overblur (Mipmap 用了近似)、各向异性过滤 (矩形区域)&lt;/label&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;
&lt;p&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_9&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_9&#34;&gt; P10    环境光照 (环境光纹理)、cubemap、凹凸贴图、位移贴图、几何？？？&lt;/label&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/div&gt;
&lt;div class=&#34;tab&#34; data-id=&#34;id1&#34; data-title=&#34;P11——P15&#34;&gt;
&lt;ul class=&#34;task-list&#34;&gt;
&lt;li class=&#34;task-list-item&#34;&gt;
&lt;p&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_10&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_10&#34;&gt; P11&lt;/label&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;
&lt;p&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_11&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_11&#34;&gt; P12&lt;/label&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;
&lt;p&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_12&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_12&#34;&gt; P13&lt;/label&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;
&lt;p&gt;&lt;input type=&#34;checkbox&#34; id=&#34;cbx_13&#34; disabled=&#34;true&#34; /&gt;&lt;label for=&#34;cbx_13&#34;&gt; P14&lt;/label&gt;&lt;/p&gt;
&lt;/li&gt;
&lt;li class=&#34;task-list-item&#34;&gt;
